using ContractManagement.Domain.Contracts; using Microsoft.EntityFrameworkCore; using Microsoft.EntityFrameworkCore.Metadata.Builders;
namespace ContractManagement.Infrastructure.Persistence.Configurations;
public sealed class ContractConfiguration:IEntityTypeConfiguration<Contract>{public void Configure(EntityTypeBuilder<Contract>b){b.ToTable("Contracts",t=>{t.HasCheckConstraint("CK_Contracts_EndTime","[EndTime] IS NULL OR [StartTime] IS NULL OR [EndTime] >= [StartTime]");t.HasCheckConstraint("CK_Contracts_ContractValue","[ContractValue] IS NULL OR [ContractValue] >= 0");});b.HasKey(x=>x.Id);b.Property(x=>x.ContractNumber).HasMaxLength(50).IsRequired();b.Property(x=>x.AreaCode).HasMaxLength(20).IsRequired();b.Property(x=>x.VehiclePlate).HasMaxLength(20);b.Property(x=>x.VehicleCode).HasMaxLength(30);b.Property(x=>x.PickupLocation).HasMaxLength(500);b.Property(x=>x.DropoffLocation).HasMaxLength(500);b.Property(x=>x.ContractValue).HasPrecision(18,2);b.Property(x=>x.PaymentMethod).HasMaxLength(100);b.Property(x=>x.Note).HasMaxLength(2000);b.Property(x=>x.ContractContentSnapshot).HasColumnType("nvarchar(max)").IsRequired();b.Property(x=>x.ContractDataJson).HasColumnType("nvarchar(max)").IsRequired();b.Property(x=>x.ContractHash).HasMaxLength(128);b.Property(x=>x.PdfFileUrl).HasMaxLength(500);b.Property(x=>x.CancelReason).HasMaxLength(1000);b.Property(x=>x.RowVersion).IsRowVersion();b.HasOne(x=>x.ContractType).WithMany(x=>x.Contracts).HasForeignKey(x=>x.ContractTypeId).OnDelete(DeleteBehavior.Restrict);b.HasOne(x=>x.ContractTemplate).WithMany(x=>x.Contracts).HasForeignKey(x=>x.ContractTemplateId).OnDelete(DeleteBehavior.Restrict);b.HasOne(x=>x.Customer).WithMany(x=>x.Contracts).HasForeignKey(x=>x.CustomerId).OnDelete(DeleteBehavior.Restrict);b.HasOne(x=>x.Driver).WithMany(x=>x.Contracts).HasForeignKey(x=>x.DriverId).OnDelete(DeleteBehavior.Restrict);b.HasIndex(x=>x.ContractNumber).IsUnique().HasDatabaseName("UX_Contracts_ContractNumber");b.HasIndex(x=>new{x.DriverId,x.Status,x.CreatedAt}).IsDescending(false,false,true).IncludeProperties(x=>new{x.ContractNumber,x.CustomerId,x.ContractTypeId,x.ContractValue}).HasDatabaseName("IX_Contracts_Driver_Status_CreatedAt");b.HasIndex(x=>new{x.AreaCode,x.CreatedAt}).IsDescending(false,true).IncludeProperties(x=>new{x.Status,x.ContractNumber,x.DriverId,x.ContractValue}).HasDatabaseName("IX_Contracts_Area_CreatedAt");b.HasIndex(x=>new{x.CustomerId,x.CreatedAt}).IsDescending(false,true).HasDatabaseName("IX_Contracts_Customer_CreatedAt");b.HasIndex(x=>new{x.Status,x.CompletedAt}).HasFilter("[CompletedAt] IS NOT NULL").HasDatabaseName("IX_Contracts_Status_CompletedAt");b.HasIndex(x=>x.ContractHash).HasFilter("[ContractHash] IS NOT NULL").HasDatabaseName("IX_Contracts_ContractHash");b.HasQueryFilter(x=>!x.IsDeleted);}}
